/**
 * Solana Payment Verification Service
 *
 * Verifies Devnet Solana transactions using Helius RPC.
 * Ensures:
 *  1. Transaction was successful
 *  2. Correct recipient (merchant public key)
 *  3. Correct amount of lamports transferred
 */

import { Connection, PublicKey } from "@solana/web3.js";

/**
 * Merchant public key that receives SOL payments.
 * Loaded from SOLANA_MERCHANT_ADDRESS in server/.env.
 * Must match the client's VITE_SOLANA_MERCHANT_ADDRESS in client/.env.
 * The server is the AUTHORITATIVE source - client value is only used to build the tx.
 */
const MERCHANT_ADDRESS = process.env.SOLANA_MERCHANT_ADDRESS || "YourMerchantAddressHere";

/**
 * The Solana network this server is configured to accept payments on.
 * Loaded from SOLANA_NETWORK in server/.env.
 * Used to cross-validate the network field sent by the client.
 * Valid values: devnet | testnet | mainnet-beta
 */
const CONFIGURED_NETWORK = (process.env.SOLANA_NETWORK as "devnet" | "testnet" | "mainnet-beta" | undefined) ?? "devnet";

/**
 * Tier pricing in SOL.
 *
 * [WARNING] MUST stay in sync with `TIER_SOL_AMOUNTS` in
 *     `client/src/components/payment/SolanaPaymentFlow.tsx`.
 *     If you change a value here, update the client constant too, and vice versa.
 */
const TIER_SOL_AMOUNTS: Record<"Lite" | "Plus" | "Pro", number> = {
  Lite: 0.001,  // 0.001 SOL
  Plus: 0.005,  // 0.005 SOL
  Pro:  0.01,   // 0.01 SOL
};

// Convert SOL to lamports
const LAMPORTS_PER_SOL = 1_000_000_000;

interface TransactionVerification {
  valid: boolean;
  reason?: string;
  amountSol?: number;
  amountUsd?: number;
  merchantAddress?: string;
}

/**
 * Create a connection to Solana RPC based on network.
 * Uses HELIUS_API_KEY for devnet/mainnet, public API for testnet.
 */
function createSolanaConnection(network: "devnet" | "testnet" | "mainnet-beta"): Connection {
  if (network === "testnet") {
    // Helius doesn't support testnet natively, use Solana public API
    return new Connection("https://api.testnet.solana.com", "confirmed");
  }

  const apiKeyRaw = process.env.HELIUS_API_KEY;
  if (!apiKeyRaw) {
    throw new Error("HELIUS_API_KEY is not configured");
  }
  // HELIUS_API_KEY may be a comma-separated list of keys; use the first valid one
  const apiKey = apiKeyRaw.split(",").map((k) => k.trim()).find((k) => k.length > 0);
  if (!apiKey) {
    throw new Error("HELIUS_API_KEY contains no valid key");
  }
  
  // Use Helius endpoint
  const subdomain = network === "mainnet-beta" ? "mainnet" : "devnet";
  const rpcUrl = `https://${subdomain}.helius-rpc.com/?api-key=${apiKey}`;
  return new Connection(rpcUrl, "confirmed");
}

/**
 * Extract native (SOL) transfers from a parsed transaction.
 * Looks for SystemProgram transfer instructions.
 */
function extractNativeTransfers(
  transaction: { meta?: { preBalances?: number[]; postBalances?: number[]; innerInstructions?: unknown[] | null } | null; transaction: { message: { accountKeys: { toString(): string }[] } } },
): Array<{
  from: string;
  to: string;
  lamports: number;
}> {
  const transfers: Array<{
    from: string;
    to: string;
    lamports: number;
  }> = [];

  try {
    const meta = transaction.meta;
    // Note: do NOT bail on !meta.innerInstructions here.
    // A plain SystemProgram.transfer produces NO innerInstructions at all,
    // so this guard was always returning an empty array for normal SOL transfers.
    if (!meta) {
      return transfers;
    }

    // Process pre-token balances to detect native transfers
    const preBalances = meta.preBalances || [];
    const postBalances = meta.postBalances || [];
    const accountKeys = transaction.transaction.message.accountKeys || [];

    if (preBalances.length === accountKeys.length && postBalances.length === accountKeys.length) {
      for (let i = 0; i < accountKeys.length; i++) {
        const diff = preBalances[i] - postBalances[i];
        if (diff > 0) {
          // This account sent lamports
          const sender = accountKeys[i].toString();
          // Look for where these lamports went (positive balance change)
          for (let j = 0; j < accountKeys.length; j++) {
            const recipientDiff = postBalances[j] - preBalances[j];
            if (recipientDiff === diff) {
              const recipient = accountKeys[j].toString();
              transfers.push({
                from: sender,
                to: recipient,
                lamports: diff,
              });
              break;
            }
          }
        }
      }
    }
  } catch (err) {
    console.warn("[extractNativeTransfers] Error parsing transaction:", err);
  }

  return transfers;
}

/**
 * Verify a Solana Devnet transaction.
 *
 * @param txId - Transaction signature
 * @param tier - Subscription tier (determines expected amount)
 * @returns Verification result with details
 */
export async function verifySolanaTransaction(
  txId: string,
  tier: "Lite" | "Plus" | "Pro",
  network: "devnet" | "testnet" | "mainnet-beta" = "devnet"
): Promise<TransactionVerification> {
  try {
    // -- Guard 0: Network mismatch between client claim and server config -----
    // The client sends the network it signed on. The server must only accept
    // transactions on the network it is configured for (SOLANA_NETWORK in .env).
    // This prevents a client from spoofing the network field to bypass verification.
    if (network !== CONFIGURED_NETWORK) {
      console.warn(
        `[verifySolanaTransaction] Network mismatch: client sent "${network}" ` +
        `but server is configured for "${CONFIGURED_NETWORK}".`
      );
      return {
        valid: false,
        reason:
          `Network mismatch: server expects "${CONFIGURED_NETWORK}" transactions, ` +
          `but received a claim for "${network}". ` +
          `Ensure VITE_SOLANA_NETWORK (client) and SOLANA_NETWORK (server) match.`,
      };
    }

    // -- Guard 1: Validate merchant address is a valid Solana public key -----
    try {
      new PublicKey(MERCHANT_ADDRESS);
    } catch {
      console.error("[verifySolanaTransaction] Invalid merchant address:", MERCHANT_ADDRESS);
      return {
        valid: false,
        reason: "Merchant address is not configured properly on the server",
      };
    }

    // TODO: Replace hardcoded amounts with real USD->SOL conversion for Mainnet.
    const expectedAmountSol = TIER_SOL_AMOUNTS[tier];
    const expectedAmountLamports = Math.floor(expectedAmountSol * LAMPORTS_PER_SOL);

    // Create connection to RPC
    const connection = createSolanaConnection(network);

    // Fetch parsed transaction
    console.log("[verifySolanaTransaction] Fetching transaction:", txId);
    const transaction = await connection.getParsedTransaction(txId, {
      commitment: "confirmed",
      maxSupportedTransactionVersion: 0,
    });

    if (!transaction) {
      return {
        valid: false,
        reason: "Transaction not found or not confirmed yet",
      };
    }

    // Check transaction status
    const meta = transaction.meta;
    if (!meta) {
      return {
        valid: false,
        reason: "Transaction metadata not available",
      };
    }

    // Check if transaction was successful (no error)
    if (meta.err !== null) {
      const errorMsg = meta.err
        ? typeof meta.err === "string"
          ? meta.err
          : JSON.stringify(meta.err)
        : "Unknown error";
      console.warn("[verifySolanaTransaction] Transaction failed:", errorMsg);
      return {
        valid: false,
        reason: `Transaction failed: ${errorMsg}`,
      };
    }

    // Look for the transfer instruction
    // Check both top-level and inner instructions
    let transferFound = false;
    let actualAmount = 0;
    let recipientAddress = "";

    try {
      // First, try to find parsed token transfer instructions
      const instructions = transaction.transaction.message.instructions || [];
      const innerInstructions = meta.innerInstructions || [];

      // Check for SystemProgram transfer in parsed format
      for (const inst of instructions) {
        const instruction = inst as any;
        if (
          instruction.program === "system" &&
          instruction.parsed?.type === "transfer"
        ) {
          const info = instruction.parsed.info;
          if (
            info.destination === MERCHANT_ADDRESS &&
            info.lamports >= expectedAmountLamports
          ) {
            transferFound = true;
            actualAmount = info.lamports;
            recipientAddress = info.destination;
            break;
          }
        }
      }

      // If not found in top-level, check inner instructions
      if (!transferFound && innerInstructions.length > 0) {
        for (const inner of innerInstructions) {
          for (const inst of inner.instructions || []) {
            const instruction = inst as any;
            if (
              instruction.program === "system" &&
              instruction.parsed?.type === "transfer"
            ) {
              const info = instruction.parsed.info;
              if (
                info.destination === MERCHANT_ADDRESS &&
                info.lamports >= expectedAmountLamports
              ) {
                transferFound = true;
                actualAmount = info.lamports;
                recipientAddress = info.destination;
                break;
              }
            }
          }
          if (transferFound) break;
        }
      }

      // Fallback: check native transfers if parsed format not available
      if (!transferFound) {
        const nativeTransfers = extractNativeTransfers(transaction);
        for (const transfer of nativeTransfers) {
          if (
            transfer.to === MERCHANT_ADDRESS &&
            transfer.lamports >= expectedAmountLamports
          ) {
            transferFound = true;
            actualAmount = transfer.lamports;
            recipientAddress = transfer.to;
            break;
          }
        }
      }
    } catch (parseErr) {
      console.warn("[verifySolanaTransaction] Error parsing instructions:", parseErr);
      // Try fallback method
      const nativeTransfers = extractNativeTransfers(transaction);
      for (const transfer of nativeTransfers) {
        if (
          transfer.to === MERCHANT_ADDRESS &&
          transfer.lamports >= expectedAmountLamports
        ) {
          transferFound = true;
          actualAmount = transfer.lamports;
          recipientAddress = transfer.to;
          break;
        }
      }
    }

    if (!transferFound) {
      console.warn("[verifySolanaTransaction] No valid transfer found", {
        txId,
        tier,
        expectedAmount: expectedAmountLamports,
        merchantAddress: MERCHANT_ADDRESS,
      });
      return {
        valid: false,
        reason: `No transfer of at least ${expectedAmountSol} SOL to merchant address found`,
      };
    }

    const actualAmountSol = actualAmount / LAMPORTS_PER_SOL;

    console.log("[verifySolanaTransaction] Transaction verified successfully", {
      txId,
      tier,
      amount: actualAmountSol,
      merchant: recipientAddress,
    });

    return {
      valid: true,
      amountSol: actualAmountSol,
      amountUsd: actualAmountSol * 100, // Placeholder: 1 SOL = $100 (adjust as needed)
      merchantAddress: recipientAddress,
    };
  } catch (err: any) {
    console.error("[verifySolanaTransaction] Error:", err);
    return {
      valid: false,
      reason: err.message || "An error occurred while verifying the transaction",
    };
  }
}

// server/src/services/stripe.service.ts
import Stripe from "stripe";

// Lazily initialised so the server boots even without a key in dev.
let _stripe: Stripe | null = null;

export function getStripe(): Stripe {
  const key = process.env.STRIPE_SECRET_KEY ?? "";
  if (!key) {
    throw new Error("STRIPE_SECRET_KEY is not configured");
  }
  if (!_stripe) {
    _stripe = new Stripe(key);
  }
  return _stripe;
}

export function constructEvent(
  payload: string | Buffer,
  header: string,
  secret: string,
): Stripe.Event {
  const stripe = getStripe();
  return stripe.webhooks.constructEvent(payload, header, secret);
}

/**
 * Find or create a Stripe Customer for the given user.
 * Returns the Stripe Customer ID.
 */
export async function findOrCreateStripeCustomer(
  userId: string,
  existingCustomerId: string | null | undefined,
  email?: string | null,
): Promise<string> {
  const stripe = getStripe();

  if (existingCustomerId) {
    return existingCustomerId;
  }

  const customer = await stripe.customers.create({
    metadata: { yocaUserId: userId },
    ...(email ? { email } : {}),
  });

  return customer.id;
}

function getPriceIdForTier(tier: string): string {
  switch (tier) {
    case "Lite":
      return process.env.STRIPE_PRICE_LITE || "price_lite_test";
    case "Plus":
      return process.env.STRIPE_PRICE_PLUS || "price_plus_test";
    case "Pro":
      return process.env.STRIPE_PRICE_PRO || "price_pro_test";
    default:
      throw new Error(`Unknown pricing tier: ${tier}`);
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// SetupIntent flow (replaces the broken PaymentIntent-on-invoice approach)
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Step 1 of the new flow.
 * Creates a SetupIntent so the frontend can securely collect a payment method.
 * The client_secret is passed to Stripe Elements → confirmSetup().
 * 
 * @param stripeCustomerId - Stripe customer ID
 * @param paymentMethod - Optional specific payment method to include ('card' or 'us_bank_account').
 *                        If omitted, both are included.
 */
export async function createSetupIntent(
  stripeCustomerId: string,
  paymentMethod?: "card" | "us_bank_account"
): Promise<Stripe.SetupIntent> {
  const stripe = getStripe();
  const paymentMethodTypes = paymentMethod
    ? [paymentMethod]
    : ["card", "us_bank_account"];

  return stripe.setupIntents.create({
    customer: stripeCustomerId,
    usage: "off_session",           // will be reused for recurring charges
    payment_method_types: paymentMethodTypes,
  });
}

export type ActivateSubscriptionOptions = {
  userId: string;
  stripeCustomerId: string;
  paymentMethodId: string;         // confirmed pm_xxx from frontend
  tier: string;
};

/**
 * Step 2 of the new flow.
 * Attaches the confirmed PaymentMethod to the customer, sets it as the default,
 * then creates the subscription. Because a valid PM is already attached,
 * Stripe charges immediately and the subscription status goes to "active".
 */
export async function activateSubscription(
  opts: ActivateSubscriptionOptions,
): Promise<Stripe.Subscription> {
  const stripe = getStripe();
  const priceId = getPriceIdForTier(opts.tier);

  // 1. Attach the payment method to the customer (idempotent if already attached)
  await stripe.paymentMethods.attach(opts.paymentMethodId, {
    customer: opts.stripeCustomerId,
  });

  // 2. Set it as the customer's default invoice payment method
  await stripe.customers.update(opts.stripeCustomerId, {
    invoice_settings: { default_payment_method: opts.paymentMethodId },
  });

  // 3. Create the subscription — it will charge immediately and become "active"
  const subscription = await stripe.subscriptions.create({
    customer: opts.stripeCustomerId,
    items: [{ price: priceId }],
    default_payment_method: opts.paymentMethodId,
    metadata: {
      yocaUserId: opts.userId,
      tier: opts.tier,
    },
    // Expand to ensure we get all fields
    expand: ["latest_invoice"],
  });

  console.log("[activateSubscription] Subscription created:", subscription.id, "Status:", subscription.status);
  
  return subscription;
}

// ─────────────────────────────────────────────────────────────────────────────
// Existing helpers (unchanged)
// ─────────────────────────────────────────────────────────────────────────────

export async function retrievePaymentIntent(id: string) {
  const stripe = getStripe();
  return await stripe.paymentIntents.retrieve(id);
}

export async function cancelSubscription(subscriptionId: string) {
  const stripe = getStripe();
  return await stripe.subscriptions.update(subscriptionId, {
    cancel_at_period_end: true,
  });
}

export async function previewSubscriptionUpgrade(subscriptionId: string, newTier: string) {
  const stripe = getStripe();
  const subscription = await stripe.subscriptions.retrieve(subscriptionId);
  const prorationDate = Math.floor(Date.now() / 1000);
  const preview = await stripe.invoices.createPreview({
    subscription: subscriptionId,
    subscription_details: {
      items: [{
        id: subscription.items.data[0].id,
        price: getPriceIdForTier(newTier),
      }],
      proration_behavior: "always_invoice",
      proration_date: prorationDate,
    },
  });
  const prorations = preview.lines.data.filter(
    (line) => line.parent?.subscription_item_details?.proration,
  );

  return {
    amountDue: preview.amount_due,
    creditAmount: Math.abs(prorations.filter((line) => line.amount < 0).reduce((sum, line) => sum + line.amount, 0)),
    chargeAmount: prorations.filter((line) => line.amount > 0).reduce((sum, line) => sum + line.amount, 0),
    currency: preview.currency,
    prorationDate,
  };
}

export async function upgradeSubscription(
  subscriptionId: string,
  newTier: string,
  prorationDate?: number,
) {
  const stripe = getStripe();
  const subscription = await stripe.subscriptions.retrieve(subscriptionId);
  const newPriceId = getPriceIdForTier(newTier);
  const defaultPaymentMethod = subscription.default_payment_method;
  const paymentMethod = typeof defaultPaymentMethod === "string"
    ? await stripe.paymentMethods.retrieve(defaultPaymentMethod)
    : defaultPaymentMethod;
  const isBankPayment = paymentMethod?.type === "us_bank_account";

  const updatedSubscription = await stripe.subscriptions.update(subscriptionId, {
    items: [
      {
        id: subscription.items.data[0].id,
        price: newPriceId,
      },
    ],
    proration_behavior: "always_invoice",
    ...(prorationDate ? { proration_date: prorationDate } : {}),
    // Stripe pending updates don't support US bank accounts.
    payment_behavior: isBankPayment ? "error_if_incomplete" : "pending_if_incomplete",
    metadata: {
      ...subscription.metadata,
      tier: newTier,
    },
    expand: ["latest_invoice"],
  });

  const latestInvoice = updatedSubscription.latest_invoice;
  const invoiceId =
    typeof latestInvoice === "string" ? latestInvoice : latestInvoice?.id;
  const invoice = invoiceId
    ? await stripe.invoices.retrieve(invoiceId, {
        expand: ["payments.data.payment.payment_intent"],
      })
    : undefined;
  const invoicePayment = (invoice as any)?.payments?.data?.find(
    (payment: any) => payment.is_default,
  ) ?? (invoice as any)?.payments?.data?.[0];
  const paymentIntent = invoicePayment?.payment?.payment_intent as
    | Stripe.PaymentIntent
    | string
    | undefined;

  return {
    subscription: updatedSubscription,
    invoice,
    clientSecret:
      typeof paymentIntent === "object"
        ? paymentIntent.client_secret
        : (invoice as any)?.confirmation_secret?.client_secret,
    applied: !updatedSubscription.pending_update,
    processing:
      isBankPayment &&
      typeof paymentIntent === "object" &&
      paymentIntent.status === "processing",
  };
}

// server/src/services/subscription.service.ts
import { db } from "@sv/db/index.js";
import { subscriptions, paymentHistory, users } from "@sv/db/schema.js";
import { and, asc, desc, eq, isNotNull, isNull, sql } from "drizzle-orm";

export async function getUserSubscription(userId: string) {
  const [sub] = await db
    .select()
    .from(subscriptions)
    .where(eq(subscriptions.userId, userId))
    .orderBy(
      sql<number>`case
        when ${subscriptions.status} = 'active' then 0
        when ${subscriptions.status} = 'trialing' then 1
        when ${subscriptions.status} = 'past_due' then 2
        when ${subscriptions.status} = 'incomplete' then 3
        when ${subscriptions.status} = 'unpaid' then 4
        when ${subscriptions.status} = 'paused' then 5
        when ${subscriptions.status} = 'canceled' then 6
        else 7
      end`,
      asc(subscriptions.cancelAtPeriodEnd),
      desc(subscriptions.currentPeriodEnd),
      desc(subscriptions.updatedAt),
      desc(subscriptions.createdAt),
    )
    .limit(1);
  return sub || null;
}

export async function getUserPaymentHistory(userId: string) {
  return await db
    .select({
      id: paymentHistory.id,
      userId: paymentHistory.userId,
      subscriptionId: paymentHistory.subscriptionId,
      stripePaymentIntentId: paymentHistory.stripePaymentIntentId,
      stripeInvoiceId: paymentHistory.stripeInvoiceId,
      amountCents: paymentHistory.amountCents,
      currency: paymentHistory.currency,
      status: paymentHistory.status,
      paymentMethodDetails: paymentHistory.paymentMethodDetails,
      createdAt: paymentHistory.createdAt,
      planTier: subscriptions.planTier,
    })
    .from(paymentHistory)
    .leftJoin(
      subscriptions,
      eq(paymentHistory.subscriptionId, subscriptions.id),
    )
    .where(eq(paymentHistory.userId, userId))
    .orderBy(desc(paymentHistory.createdAt));
}

export async function refreshPendingPaymentHistory(historyRows: Array<any>) {
  const pendingInvoiceIds = historyRows
    .filter((row) => row.status === "pending" && row.stripeInvoiceId)
    .map((row) => row.stripeInvoiceId as string);
  if (pendingInvoiceIds.length === 0) return;

  const { getStripe } = await import("@sv/services/stripe.service.js");
  const stripe = getStripe();
  for (const invoiceId of pendingInvoiceIds) {
    const invoice = await stripe.invoices.retrieve(invoiceId, {
      expand: ["payments.data.payment.payment_intent"],
    });
    await recordInvoicePayment(invoice);
  }
}

export async function enrichPaymentHistoryWithStripeProduct(
  historyRows: Array<any>,
) {
  if (historyRows.length === 0) return historyRows;

  const { getStripe } = await import("@sv/services/stripe.service.js");
  const stripe = getStripe();

  const resolvePlanFromInvoice = async (invoice: any) => {
    const lines = invoice?.lines?.data ?? [];
    const getPrice = (line: any) =>
      line?.price ?? line?.pricing?.price_details?.price;
    const selectedLine =
      lines.find(
        (line: any) =>
          line.amount > 0 &&
          mapTierFromPriceId(
            typeof getPrice(line) === "string"
              ? getPrice(line)
              : getPrice(line)?.id,
          ),
      ) ?? lines.find((line: any) => line.amount > 0);
    const linePrice = getPrice(selectedLine);
    const linePriceId =
      typeof linePrice === "string" ? linePrice : linePrice?.id;
    const planTier = mapTierFromPriceId(linePriceId);
    if (planTier) return { planName: planTier, planTier };

    const lineProduct =
      selectedLine?.pricing?.price_details?.product ?? linePrice?.product;
    if (typeof lineProduct === "object" && lineProduct?.name) {
      return { planName: String(lineProduct.name), planTier: undefined };
    }
    if (typeof lineProduct === "string") {
      try {
        const product = await stripe.products.retrieve(lineProduct);
        return {
          planName: product?.name ? String(product.name) : null,
          planTier: undefined,
        };
      } catch {
        // Product lookup is optional; the invoice amount fallback remains available.
      }
    }

    return {
      planName: null,
      planTier: undefined,
    };
  };

  const enrichedRows = await Promise.all(
    historyRows.map(async (row) => {
      if (!row?.stripeInvoiceId) {
        return {
          ...row,
          planName: row?.planTier ?? null,
        };
      }

      try {
        const invoice = await stripe.invoices.retrieve(row.stripeInvoiceId);

        const { planName, planTier } = await resolvePlanFromInvoice(
          invoice as any,
        );

        return {
          ...row,
          planTier: planTier ?? null,
          planName: planName ?? planTier ?? null,
        };
      } catch {
        return {
          ...row,
          planTier: null,
          planName: null,
        };
      }
    }),
  );

  return enrichedRows;
}

export async function getUserSubscriptions(userId: string) {
  return await db
    .select()
    .from(subscriptions)
    .where(eq(subscriptions.userId, userId))
    .orderBy(desc(subscriptions.updatedAt), desc(subscriptions.createdAt));
}

async function getUserStripeCustomerId(userId: string): Promise<string | null> {
  const [user] = await db
    .select({ stripeCustomerId: users.stripeCustomerId })
    .from(users)
    .where(eq(users.id, userId))
    .limit(1);

  return user?.stripeCustomerId ?? null;
}

function mapTierFromPriceId(
  priceId: string | undefined,
): "Lite" | "Plus" | "Pro" | undefined {
  if (!priceId) return undefined;
  if (priceId === process.env.STRIPE_PRICE_LITE) return "Lite";
  if (priceId === process.env.STRIPE_PRICE_PLUS) return "Plus";
  if (priceId === process.env.STRIPE_PRICE_PRO) return "Pro";
  return undefined;
}

function getInvoiceSubscriptionId(invoice: any): string | undefined {
  const subscription =
    invoice?.subscription ??
    invoice?.parent?.subscription_details?.subscription;
  return typeof subscription === "string" ? subscription : subscription?.id;
}

function resolveSubscriptionPeriodUnix(stripeSub: any): {
  start: number | null;
  end: number | null;
} {
  const topLevelStart = stripeSub?.current_period_start;
  const topLevelEnd = stripeSub?.current_period_end;

  const firstItem = stripeSub?.items?.data?.[0];
  const itemLevelStart = firstItem?.current_period_start;
  const itemLevelEnd = firstItem?.current_period_end;

  const firstInvoiceLine = stripeSub?.latest_invoice?.lines?.data?.[0];
  const invoiceLineStart = firstInvoiceLine?.period?.start;
  const invoiceLineEnd = firstInvoiceLine?.period?.end;

  const start = topLevelStart ?? itemLevelStart ?? invoiceLineStart ?? null;
  const end = topLevelEnd ?? itemLevelEnd ?? invoiceLineEnd ?? null;

  return {
    start: typeof start === "number" ? start : null,
    end: typeof end === "number" ? end : null,
  };
}

export async function syncUserSubscriptionsFromStripe(userId: string) {
  const stripeCustomerId = await getUserStripeCustomerId(userId);
  if (!stripeCustomerId) return;

  const { getStripe } = await import("@sv/services/stripe.service.js");
  const stripe = getStripe();

  const stripeSubs = await stripe.subscriptions.list({
    customer: stripeCustomerId,
    status: "all",
    limit: 20,
  });

  for (const stripeSub of stripeSubs.data) {
    await upsertSubscription(stripeSub);
  }
}

export async function upsertSubscription(stripeSub: any) {
  const stripeCustomerId = stripeSub.customer as string;
  const yocaUserIdFromMetadata = stripeSub.metadata?.yocaUserId as
    | string
    | undefined;
  const tierFromMetadata = stripeSub.metadata?.tier as string | undefined;

  let yocaUserId = yocaUserIdFromMetadata;
  if (!yocaUserId && stripeCustomerId) {
    const [user] = await db
      .select({ id: users.id })
      .from(users)
      .where(eq(users.stripeCustomerId, stripeCustomerId))
      .limit(1);
    yocaUserId = user?.id;
  }

  const priceId = stripeSub.items?.data?.[0]?.price?.id as string | undefined;
  const tierFromPrice = mapTierFromPriceId(priceId);

  const [existingSub] = await db
    .select({ planTier: subscriptions.planTier })
    .from(subscriptions)
    .where(eq(subscriptions.stripeSubscriptionId, stripeSub.id))
    .limit(1);

  const tier = tierFromMetadata ?? tierFromPrice ?? existingSub?.planTier;
  const periodUnix = resolveSubscriptionPeriodUnix(stripeSub);

  if (!yocaUserId || !tier) return null;

  const mappedCurrentPeriodStart =
    periodUnix.start != null ? new Date(periodUnix.start * 1000) : null;
  const mappedCurrentPeriodEnd =
    periodUnix.end != null ? new Date(periodUnix.end * 1000) : null;

  const [existing] = await db
    .select()
    .from(subscriptions)
    .where(eq(subscriptions.stripeSubscriptionId, stripeSub.id))
    .limit(1);

  if (!existing) {
    const [inserted] = await db
      .insert(subscriptions)
      .values({
        userId: yocaUserId,
        stripeCustomerId,
        stripeSubscriptionId: stripeSub.id,
        planTier: tier as any,
        status: stripeSub.status,
        currentPeriodStart: mappedCurrentPeriodStart,
        currentPeriodEnd: mappedCurrentPeriodEnd,
        cancelAtPeriodEnd: stripeSub.cancel_at_period_end,
      })
      .returning();

    return inserted;
  }

  const hasStatusChanged = existing.status !== stripeSub.status;
  const hasTierChanged = existing.planTier !== tier;
  const hasCancelFlagChanged =
    existing.cancelAtPeriodEnd !== stripeSub.cancel_at_period_end;
  const hasPeriodStartChanged =
    (existing.currentPeriodStart?.getTime() ?? null) !==
    (mappedCurrentPeriodStart?.getTime() ?? null);
  const hasPeriodEndChanged =
    (existing.currentPeriodEnd?.getTime() ?? null) !==
    (mappedCurrentPeriodEnd?.getTime() ?? null);

  const shouldUpdate =
    hasStatusChanged ||
    hasTierChanged ||
    hasCancelFlagChanged ||
    hasPeriodStartChanged ||
    hasPeriodEndChanged;

  if (!shouldUpdate) {
    return existing;
  }

  const [updated] = await db
    .update(subscriptions)
    .set({
      status: stripeSub.status,
      currentPeriodStart: mappedCurrentPeriodStart,
      currentPeriodEnd: mappedCurrentPeriodEnd,
      cancelAtPeriodEnd: stripeSub.cancel_at_period_end,
      planTier: tier as any,
    })
    .where(eq(subscriptions.stripeSubscriptionId, stripeSub.id))
    .returning();

  return updated;
}

export async function recordInvoicePayment(
  invoice: any,
  statusOverride?: "succeeded" | "failed" | "pending",
) {
  if (!invoice.customer) return null;

  // We need to find the user id from the subscription
  const subId = getInvoiceSubscriptionId(invoice);
  const [sub] = subId
    ? await db
        .select()
        .from(subscriptions)
        .where(eq(subscriptions.stripeSubscriptionId, subId))
        .limit(1)
    : [null];

  let userId = sub?.userId;
  const subscriptionId: string | null = sub?.id ?? null;

  if (!userId && invoice.customer) {
    const stripeCustomerId =
      typeof invoice.customer === "string"
        ? invoice.customer
        : invoice.customer.id;
    const [user] = await db
      .select({ id: users.id })
      .from(users)
      .where(eq(users.stripeCustomerId, stripeCustomerId))
      .limit(1);
    userId = user?.id;
  }

  if (!userId) return null;

  const invoicePayment =
    invoice.payments?.data?.find((payment: any) => payment.is_default) ??
    invoice.payments?.data?.[0];
  const paymentIntent =
    invoice.payment_intent ?? invoicePayment?.payment?.payment_intent;
  const paymentIntentId = paymentIntent
    ? typeof paymentIntent === "string"
      ? paymentIntent
      : paymentIntent.id
    : null;

  let brand, last4;
  if (
    typeof paymentIntent === "object" &&
    paymentIntent.payment_method_details
  ) {
    brand = paymentIntent.payment_method_details?.card?.brand;
    last4 = paymentIntent.payment_method_details?.card?.last4;
  }

  const paymentStatus =
    statusOverride ??
    (invoice.status === "paid" || invoicePayment?.status === "paid"
      ? "succeeded"
      : invoice.status === "void" ||
          invoice.status === "uncollectible" ||
          invoicePayment?.status === "canceled"
        ? "failed"
        : "pending");

  await db
    .insert(paymentHistory)
    .values({
      userId,
      subscriptionId,
      stripePaymentIntentId: paymentIntentId,
      stripeInvoiceId: invoice.id,
      amountCents: invoice.amount_paid || invoice.amount_due || invoice.total || 0,
      currency: invoice.currency,
      status: paymentStatus,
      paymentMethodDetails: brand || last4 ? { brand, last4 } : null,
    })
    .onConflictDoUpdate({
      target: paymentHistory.stripeInvoiceId,
      set: {
        amountCents: invoice.amount_paid || invoice.amount_due || invoice.total || 0,
        currency: invoice.currency,
        status: paymentStatus,
        ...(subscriptionId ? { subscriptionId } : {}),
        ...(paymentIntentId ? { stripePaymentIntentId: paymentIntentId } : {}),
        ...(brand || last4 ? { paymentMethodDetails: { brand, last4 } } : {}),
      },
    });
}

export async function backfillUserPaymentHistory(userId: string) {
  const { getStripe } = await import("@sv/services/stripe.service.js");
  const stripe = getStripe();

  const stripeCustomerId = await getUserStripeCustomerId(userId);

  const seenInvoiceIds = new Set<string>();

  if (stripeCustomerId) {
    const invoices = await stripe.invoices.list({
      customer: stripeCustomerId,
      limit: 100,
    });

    for (const invoice of invoices.data) {
      const stripeInvoice = invoice as any;
      seenInvoiceIds.add(stripeInvoice.id);

      // Ensure corresponding subscription exists/updated in our DB first.
      const stripeSubId = getInvoiceSubscriptionId(stripeInvoice);
      if (stripeSubId) {
        try {
          const stripeSub = await stripe.subscriptions.retrieve(stripeSubId);
          await upsertSubscription(stripeSub);
        } catch (subErr) {
          console.warn("Failed to sync subscription during history backfill", {
            stripeSubId,
            subErr,
          });
        }
      }

      const fullInvoice = await stripe.invoices.retrieve(stripeInvoice.id, {
        expand: ["payments.data.payment.payment_intent"],
      });
      await recordInvoicePayment(fullInvoice);
    }
  }

  // Fallback path: backfill by known subscription IDs in DB.
  const localSubs = await db
    .select({ stripeSubscriptionId: subscriptions.stripeSubscriptionId })
    .from(subscriptions)
    .where(eq(subscriptions.userId, userId))
    .orderBy(desc(subscriptions.createdAt));

  for (const localSub of localSubs) {
    const subInvoices = await stripe.invoices.list({
      subscription: localSub.stripeSubscriptionId,
      limit: 20,
    });

    for (const invoice of subInvoices.data) {
      const stripeInvoice = invoice as any;
      if (seenInvoiceIds.has(stripeInvoice.id)) continue;

      const fullInvoice = await stripe.invoices.retrieve(stripeInvoice.id, {
        expand: ["payments.data.payment.payment_intent"],
      });
      await recordInvoicePayment(fullInvoice);
    }
  }
}

export async function repairPaymentHistorySubscriptionLinks(userId: string) {
  const rows = await db
    .select({
      id: paymentHistory.id,
      stripeInvoiceId: paymentHistory.stripeInvoiceId,
    })
    .from(paymentHistory)
    .where(
      and(
        eq(paymentHistory.userId, userId),
        isNull(paymentHistory.subscriptionId),
        isNotNull(paymentHistory.stripeInvoiceId),
      ),
    )
    .orderBy(desc(paymentHistory.createdAt));

  if (rows.length === 0) return;

  const { getStripe } = await import("@sv/services/stripe.service.js");
  const stripe = getStripe();

  for (const row of rows) {
    if (!row.stripeInvoiceId) continue;

    try {
      const invoice = await stripe.invoices.retrieve(row.stripeInvoiceId, {
        expand: ["subscription"],
      });

      const stripeSubId = getInvoiceSubscriptionId(invoice);

      if (!stripeSubId) continue;

      const stripeSub = await stripe.subscriptions.retrieve(stripeSubId);
      const localSub = await upsertSubscription(stripeSub);
      if (!localSub?.id) continue;

      await db
        .update(paymentHistory)
        .set({ subscriptionId: localSub.id })
        .where(eq(paymentHistory.id, row.id));
    } catch (err) {
      console.warn("Failed to repair payment history row", {
        paymentHistoryId: row.id,
        stripeInvoiceId: row.stripeInvoiceId,
        err,
      });
    }
  }
}

