import { getTrackedApiResult } from "@sv/middlewares/validation.js";
import type { WalletTimePeriod } from "@sv/services/wallet/dtos/walletDataObjects.js";
import { zrn_WalletBalanceChartSchema } from "../_types/wallet-raw-responses.js";
import { db } from "@sv/db/index.js";
import {
    walletTokenBalanceMonthHistory,
    walletTokenBalanceWeekHistory,
    zerionTokenList,
} from "@sv/db/schema.js";
import { rlFetch } from "@sv/util/rate-limit.js";
import dayjs from "dayjs";
import { and, between, eq, inArray } from "drizzle-orm";
import {
    WALLET_BALANCE_HISTORY_STORED_TTL_MS,
    ZRN_SOL_FUNGIBLE_ID,
} from "@sv/config/constants.js";
import * as zrn from "@sv/util/util-zerion.js";
import { zrn_FungiblesResponseSchema } from "../_types/token-raw-responses.js";
import { SOL_NATIVE_ALIAS_MINT } from "./wallet.constants.js";

type WalletTokenBalanceHistory = Record<
  string,
  {
    usdValue: number;
    timestampMs: number;
  }[]
> | null;

async function getZerionId(
  tokenAddresses: string[],
): Promise<Record<string, string>> {
  const fungibleImplementationAddresses = tokenAddresses.filter(
    (tokenAddress) => tokenAddress !== SOL_NATIVE_ALIAS_MINT,
  );
  const nativeSolId: Record<string, string> = {};
  if (tokenAddresses.includes(SOL_NATIVE_ALIAS_MINT)) {
    nativeSolId[SOL_NATIVE_ALIAS_MINT] = ZRN_SOL_FUNGIBLE_ID;
  }

  if (fungibleImplementationAddresses.length == 0) {
    return nativeSolId;
  }

  const res = await db
    .select()
    .from(zerionTokenList)
    .where(
      inArray(
        zerionTokenList.tokenAddress,
        fungibleImplementationAddresses,
      ),
    );

  if (res.length == 0) {
    return {
      ...(await fetchZerionId(fungibleImplementationAddresses)),
      ...nativeSolId,
    };
  }
  return {
    ...Object.fromEntries(
      res.map((entry) => [entry.tokenAddress, entry.zerionId]),
    ),
    ...nativeSolId,
  };
}

async function fetchZerionId(
  tokenAddresses: string[],
): Promise<Record<string, string>> {
  // TODO: warn about token addresses limit of 25
  const url = zrn.getEndpoint("/fungibles/");
  const req = new URL(url);

  // Filter by chain and addresses (comma-separated)
  req.search = new URLSearchParams({
    "filter[chain_ids]": "solana",
    "filter[fungible_implementations]": tokenAddresses
      .map((addr) => `solana:${addr}`)
      .join(","),
  }).toString();

  const resp = await fetch(req, {
    method: "GET",
    headers: zrn.getRequiredHeaders(),
  });

  const res = await getTrackedApiResult(zrn_FungiblesResponseSchema, resp);

  if (!res) {
    return {};
  }

  // Build a map: token address (from implementations) -> Zerion ID (uuid)
  const idMap: Record<string, string> = {};
  for (const item of res.data) {
    const zerionId = item.id;
    // Find the Solana implementation address
    const solImpl = item.attributes.implementations.find(
      (impl) => impl.chain_id == "solana" && impl.address != null,
    );
    if (solImpl?.address) {
      idMap[solImpl.address] = zerionId;
    }
  }

  const insertValues = Object.entries(idMap).map(([addr, id]) => ({
    tokenAddress: addr,
    zerionId: id,
  }));

  await db.insert(zerionTokenList).values(insertValues).onConflictDoNothing();

  return idMap;
}

export async function getWalletTokenBalanceHistory(
  address: string,
  tokenAddresses: string[],
  timePeriod: WalletTimePeriod = "30D",
): Promise<WalletTokenBalanceHistory> {
  // TODO: enforce this
  const toZrnChartPeriod: Record<any, "week" | "month"> = {
    "7D": "week",
    "30D": "month",
  };

  const zrnPeriod = toZrnChartPeriod[timePeriod];

  const nowUtc = dayjs().utc();
  const end = nowUtc.valueOf();
  const start = nowUtc.subtract(1, zrnPeriod).valueOf();
  const thresholdDateMs = end - WALLET_BALANCE_HISTORY_STORED_TTL_MS;

  const balanceTable =
    zrnPeriod == "week"
      ? walletTokenBalanceWeekHistory
      : walletTokenBalanceMonthHistory;

  const res = await db
    .select()
    .from(balanceTable)
    .where(
      and(
        between(balanceTable.timestampMs, start, end),
        eq(balanceTable.walletAddress, address),
        inArray(balanceTable.tokenAddress, tokenAddresses),
      ),
    )
    .orderBy(balanceTable.tokenAddress, balanceTable.timestampMs);

  if (res.length == 0) {
    const fetched = await fetchWalletTokenBalanceHistory(
      address,
      tokenAddresses,
      zrnPeriod,
    );
    if (!fetched) {
      return null;
    }
    const normalizedGrouped = normalizeByDay(fetched);
    return alignEndTimestamps(normalizedGrouped);
  }

  const grouped = {} as NonNullable<WalletTokenBalanceHistory>;
  const latestUpdateByToken = new Map<string, number | null>();

  for (const value of res) {
    if (!grouped[value.tokenAddress]) {
      grouped[value.tokenAddress] = [];
    }

    grouped[value.tokenAddress].push({
      timestampMs: value.timestampMs,
      usdValue: value.usdValue,
    });

    const currentUpdatedAtMs = latestUpdateByToken.get(value.tokenAddress);
    const nextUpdatedAtMs = value.updatedAtMs;

    if (
      currentUpdatedAtMs == null ||
      (nextUpdatedAtMs != null && nextUpdatedAtMs > currentUpdatedAtMs)
    ) {
      latestUpdateByToken.set(value.tokenAddress, nextUpdatedAtMs);
    }
  }

  const missingTokens = tokenAddresses.filter((addr) => {
    const latestUpdatedAtMs = latestUpdateByToken.get(addr);
    return latestUpdatedAtMs == null || latestUpdatedAtMs < thresholdDateMs;
  });

  if (missingTokens.length > 0) {
    const fetched = await fetchWalletTokenBalanceHistory(
      address,
      missingTokens,
      zrnPeriod,
    );
    const merged = { ...grouped, ...fetched };
    const normalizedGrouped = normalizeByDay(merged);
    return alignEndTimestamps(normalizedGrouped);
  }

  const normalizedGrouped = normalizeByDay(grouped);
  return alignEndTimestamps(normalizedGrouped);
}

export async function fetchWalletTokenBalanceHistory(
  address: string,
  tokenAddresses: string[] = [],
  timePeriod: "week" | "month",
): Promise<WalletTokenBalanceHistory> {
  const idLookup = await getZerionId(tokenAddresses);

  if (Object.keys(idLookup).length == 0) {
    return null;
  }

  const zerionIdMap = tokenAddresses
    .map((addr) => ({ addr, id: idLookup[addr] }))
    .filter((item) => item.id);

  const resArray = await Promise.all(
    zerionIdMap.map(async ({ addr, id }) => {
      // TODO: warn about token addresses limit of 25
      const url = zrn.getEndpoint(`/wallets/${address}/charts/${timePeriod}`);
      const req = new URL(url);
      req.search = new URLSearchParams({
        currency: "usd",
        "filter[positions]": "only_simple",
        "filter[chain_ids]": "solana",
        "filter[fungible_ids]": id,
      }).toString();

      // Use the shared limiter
      const resp = await rlFetch(req, {
        rlLimiter: zrn.limiter,
        method: "GET",
        headers: zrn.getRequiredHeaders(),
        rlRetries: 3,
        rlRetryDelayMs: 500,
        rlTimeoutMs: 30000,
      });

      const res = await getTrackedApiResult(zrn_WalletBalanceChartSchema, resp);
      if (!res) {
        return res;
      }

      return { ...res, addr };
    }),
  );

  const insertValues = resArray
    .filter((entry) => !!entry)
    .flatMap((entry) =>
      entry.data.attributes.points.map((point) => ({
        walletAddress: address,
        tokenAddress: entry.addr,
        // s -> ms
        timestampMs: point[0] * 1000,
        usdValue: point[1],
      })),
    );

  const balanceTable =
    timePeriod == "week"
      ? walletTokenBalanceWeekHistory
      : walletTokenBalanceMonthHistory;

  await db.insert(balanceTable).values(insertValues).onConflictDoNothing();

  const grouped = insertValues.reduce((acc, value) => {
    if (!acc[value.tokenAddress]) {
      acc[value.tokenAddress] = [];
    }
    acc[value.tokenAddress].push({
      timestampMs: value.timestampMs,
      usdValue: value.usdValue,
    });
    return acc;
  }, {} as NonNullable<WalletTokenBalanceHistory>);

  return grouped;
}

// Group data points by UTC day, keeping only the latest point per day.
function normalizeByDay(
  grouped: NonNullable<WalletTokenBalanceHistory>,
): NonNullable<WalletTokenBalanceHistory> {
  const normalized: NonNullable<WalletTokenBalanceHistory> = {};

  for (const [tokenAddress, points] of Object.entries(grouped)) {
    const groupedByDay = new Map<
      number,
      { usdValue: number; timestampMs: number }
    >();

    for (const point of points) {
      const dayStartMs = dayjs.utc(point.timestampMs).startOf("day").valueOf();
      const existing = groupedByDay.get(dayStartMs);

      if (!existing || point.timestampMs > existing.timestampMs) {
        groupedByDay.set(dayStartMs, point);
      }
    }

    normalized[tokenAddress] = Array.from(groupedByDay.values()).sort(
      (a, b) => a.timestampMs - b.timestampMs,
    );
  }

  return normalized;
}

// Align all token series to the same oldest common timestamp.
// Truncates newer data points so all tokens have data from the same time window.
function alignEndTimestamps(
  grouped: NonNullable<WalletTokenBalanceHistory>,
): WalletTokenBalanceHistory {
  // Get all timestamp sets per token
  const tokenTimestamps = Object.values(grouped).map(
    (points) => new Set(points.map((p) => p.timestampMs)),
  );

  if (tokenTimestamps.length == 0) return grouped;

  // Find the largest timestamp that exists in every token
  let commonMax: number | null = null;
  const firstSet = tokenTimestamps[0];
  for (const ts of firstSet) {
    if (tokenTimestamps.every((set) => set.has(ts))) {
      if (commonMax == null || ts > commonMax) commonMax = ts;
    }
  }

  if (commonMax == null) {
    // No common timestamp – you may want to return empty or throw
    return null;
  }

  // Keep only points up to that common max (including it)
  const aligned: NonNullable<WalletTokenBalanceHistory> = {};
  for (const [tokenAddress, points] of Object.entries(grouped)) {
    aligned[tokenAddress] = points.filter((p) => p.timestampMs <= commonMax);
  }
  return aligned;
}

import { db } from '../db';
import { walletTransactions } from '../db/schema';
import { eq, gte } from 'drizzle-orm';

export interface WashTradePattern {
  circularTrades: number;
  sameAmountTransactions: number;
  tightTimingClusters: number;
  starTopology: boolean;
  volumeAnomaly: boolean;
}

export interface WalletSuspicion {
  wallet: string;
  volume: number;
  confidence: number;
  pattern: string;
  gnnScore: number;
}

export interface WashTradeAnalysis {
  riskScore: number;
  suspiciousWallets: WalletSuspicion[];
  transactions: any[];
  summary: {
    totalVolume: number;
    volumeAnomalies: number;
    circularTrades: number;
  };
  patterns: WashTradePattern;
}
export interface TokenTransaction {
  signature: string;
  from: string;
  to: string;
  amount: number;
  blockTime: number; // unix timestamp
  tokenMint: string;
}
class WashTradingService {
  /**
   * Detect circular trade patterns: A → B → C → A
   */
  async detectCircularTrades(
    mint: string,
    timeWindow: number = 3600000 // 1 hour in ms
  ): Promise<any[]> {
    try {
      // Query transactions for the token within time window
      const recentTxs = await db
        .select()
        .from(walletTransactions)
        .where(
          gte(walletTransactions.blockTimestamp, new Date(Date.now() - timeWindow))
        )
        .limit(1000);

      const circularPatterns: any[] = [];
      
      // Find 3-step cycles
      for (let i = 0; i < recentTxs.length; i++) {
        const tx1 = recentTxs[i];
        
        // Find next transaction from tx1.to
        const tx2 = recentTxs.find(
          (t: typeof recentTxs[0]) => t.fromAddress === tx1.toAddress && 
               t.blockTimestamp > tx1.blockTimestamp &&
               Math.abs((t.primaryTokenAmount || 0) - (tx1.primaryTokenAmount || 0)) < (tx1.primaryTokenAmount || 0) * 0.01 // Within 1%
        );
        
        if (!tx2) continue;
        
        // Find cycle back to original
        const tx3 = recentTxs.find(
          (t: typeof recentTxs[0]) => t.fromAddress === tx2.toAddress && 
               t.toAddress === tx1.fromAddress &&
               t.blockTimestamp > tx2.blockTimestamp &&
               Math.abs((t.primaryTokenAmount || 0) - (tx1.primaryTokenAmount || 0)) < (tx1.primaryTokenAmount || 0) * 0.01
        );
        
        if (tx3) {
          circularPatterns.push({
            cycle: [tx1.fromAddress, tx2.fromAddress, tx3.fromAddress],
            amounts: [tx1.primaryTokenAmount, tx2.primaryTokenAmount, tx3.primaryTokenAmount],
            timestamps: [tx1.blockTimestamp, tx2.blockTimestamp, tx3.blockTimestamp],
            avgTime: (tx3.blockTimestamp.getTime() - tx1.blockTimestamp.getTime()) / 2,
            confidence: 0.95
          });
        }
      }
      
      return circularPatterns;
    } catch (error) {
      console.error('Circular trade detection error:', error);
      return [];
    }
  }

  /**
   * Detect same-amount transaction clusters
   */
  async detectSameAmountPatterns(
    mint: string,
    tolerance: number = 0.02 // 2%
  ): Promise<Map<number, any[]>> {
    try {
      const txs = await db
        .select()
        .from(walletTransactions)
        .where(eq(walletTransactions.primaryTokenAddress, mint))
        .limit(5000);

      const sameAmountClusters = new Map<number, any[]>();
      
      for (const tx of txs) {
        const amount = tx.primaryTokenAmount || 0;
        const rounded = Math.round(amount / (amount * tolerance));
        if (!sameAmountClusters.has(rounded)) {
          sameAmountClusters.set(rounded, []);
        }
        sameAmountClusters.get(rounded)!.push(tx);
      }

      // Filter: only keep clusters with anomalous frequency
      const anomalous = new Map<number, any[]>();
      for (const [key, cluster] of sameAmountClusters.entries()) {
        if (cluster.length > 5) { // Threshold
          anomalous.set(key, cluster);
        }
      }

      return anomalous;
    } catch (error) {
      console.error('Same amount detection error:', error);
      return new Map();
    }
  }

  /**
   * Detect star topology: one hub wallet connecting many spokes
   */
  async detectStarTopology(mint: string): Promise<any> {
    try {
      const txs = await db
        .select()
        .from(walletTransactions)
        .where(eq(walletTransactions.primaryTokenAddress, mint))
        .limit(10000);

      // Count interactions per wallet
      const walletDegrees = new Map<string, { in: number; out: number }>();
      
      for (const tx of txs) {
        if (!walletDegrees.has(tx.fromAddress)) {
          walletDegrees.set(tx.fromAddress, { in: 0, out: 0 });
        }
        if (!walletDegrees.has(tx.toAddress)) {
          walletDegrees.set(tx.toAddress, { in: 0, out: 0 });
        }
        
        walletDegrees.get(tx.fromAddress)!.out++;
        walletDegrees.get(tx.toAddress)!.in++;
      }

      // Find hubs (high in + out degree)
      const hubs: any[] = [];
      for (const [wallet, degrees] of walletDegrees.entries()) {
        const totalDegree = degrees.in + degrees.out;
        if (totalDegree > 50) { // Threshold
          hubs.push({
            wallet,
            inDegree: degrees.in,
            outDegree: degrees.out,
            totalDegree,
            isHub: true
          });
        }
      }

      return hubs.sort((a, b) => b.totalDegree - a.totalDegree).slice(0, 10);
    } catch (error) {
      console.error('Star topology detection error:', error);
      return [];
    }
  }

  /**
   * Detect volume anomalies using statistical methods
   */
  async detectVolumeAnomalies(mint: string): Promise<any[]> {
    try {
      const txs = await db
        .select()
        .from(walletTransactions)
        .where(eq(walletTransactions.primaryTokenAddress, mint))
        .limit(5000);

      const amounts = txs.map((t: typeof txs[0]) => t.primaryTokenAmount || 0);
      const mean = amounts.reduce((a: number, b: number) => a + b, 0) / amounts.length;
      const variance = amounts.reduce((a: number, b: number) => a + Math.pow(b - mean, 2), 0) / amounts.length;
      const stdDev = Math.sqrt(variance);

      // Z-score > 3 is very anomalous
      const anomalies: any[] = [];
      for (const tx of txs) {
        const amount = tx.primaryTokenAmount || 0;
        const zScore = Math.abs((amount - mean) / stdDev);
        if (zScore > 2.5) {
          anomalies.push({
            hash: tx.hash,
            amount,
            zScore,
            anomalyScore: Math.min(1, zScore / 5)
          });
        }
      }

      return anomalies.sort((a, b) => b.anomalyScore - a.anomalyScore).slice(0, 20);
    } catch (error) {
      console.error('Volume anomaly detection error:', error);
      return [];
    }
  }

  /**
   * GNN-based anomaly scoring (stub - integrate with Python service)
   */
  async getGNNScores(mint: string, walletAddresses: string[]): Promise<Map<string, number>> {
    try {
      // Call Python GNN service
      const response = await fetch('http://localhost:5000/api/gnn/analyze', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ mint, wallets: walletAddresses })
      });

      if (!response.ok) throw new Error('GNN service unavailable');
      
      const data = await response.json() as { scores?: Record<string, number> };
      const scores = data.scores || {};
      return new Map(Object.entries(scores) as [string, number][]);
    } catch (error) {
      console.error('GNN scoring error:', error);
      // Fallback: return random scores for testing
      return new Map(walletAddresses.map(w => [w, Math.random()]));
    }
  }

  /**
   * Main analysis orchestration
   */
  async analyzeWashTrading(mint: string): Promise<WashTradeAnalysis> {
    const [
      circularTrades,
      sameAmountClusters,
      starHubs,
      volumeAnomalies
    ] = await Promise.all([
      this.detectCircularTrades(mint),
      this.detectSameAmountPatterns(mint),
      this.detectStarTopology(mint),
      this.detectVolumeAnomalies(mint)
    ]);

    // Collect unique suspicious wallets
    const suspiciousWallets = new Set<string>();
    
    circularTrades.forEach(ct => ct.cycle.forEach((w: string) => suspiciousWallets.add(w)));
    sameAmountClusters.forEach(cluster => {
      cluster.forEach((tx: any) => {
        suspiciousWallets.add(tx.fromAddress);
        suspiciousWallets.add(tx.toAddress);
      });
    });
    starHubs.forEach((hub: any) => suspiciousWallets.add(hub.wallet));
    volumeAnomalies.forEach(va => suspiciousWallets.add(va.hash));

    // Get GNN scores
    const gnnScores = await this.getGNNScores(mint, Array.from(suspiciousWallets));

    // Build results
    const suspiciousWalletsResult = Array.from(suspiciousWallets).map(wallet => ({
      wallet,
      volume: Math.random() * 1e6, // Calculate actual volume
      confidence: gnnScores.get(wallet) || Math.random(),
      pattern: this.determinePattern(wallet, circularTrades, starHubs),
      gnnScore: gnnScores.get(wallet) || 0
    }));

    const totalVolume = 50e6; // Calculate from transactions
    const circularCount = circularTrades.length;

    return {
      riskScore: Math.min(1, (suspiciousWalletsResult.length * 0.1) + (circularCount * 0.15)),
      suspiciousWallets: suspiciousWalletsResult.sort((a, b) => b.confidence - a.confidence).slice(0, 20),
      transactions: volumeAnomalies.slice(0, 30),
      summary: {
        totalVolume,
        volumeAnomalies: volumeAnomalies.length,
        circularTrades: circularCount
      },
      patterns: {
        circularTrades: circularCount,
        sameAmountTransactions: sameAmountClusters.size,
        tightTimingClusters: circularTrades.filter(ct => ct.avgTime < 60000).length,
        starTopology: starHubs.length > 0,
        volumeAnomaly: volumeAnomalies.length > 5
      }
    };
  }

  private determinePattern(
    wallet: string,
    circularTrades: any[],
    starHubs: any[]
  ): string {
    if (circularTrades.some(ct => ct.cycle.includes(wallet))) return 'Circular Trade';
    if (starHubs.some(h => h.wallet === wallet)) return 'Hub Wallet';
    return 'Anomalous Activity';
  }
}

